    our_files = []
    for c in contexts:
        metadata = getattr(c, "metadata", None) or {}
        fn = metadata.get("file_name") or ""
        if run_id in fn:
            our_files.append(fn)
    print(f"{label}: our_matched={sorted(our_files)}")

